447	void initializeBeamMatrices() {
448	    uint8_t msg[] = "Initializing Beam Matrices...\r\n";
449	    HAL_UART_Transmit(&huart3, msg, sizeof(msg)-1, 1000);
450	
451	    // Matrix1: Positions 1-15 (positive phase differences)
452	    for(int beam_pos = 0; beam_pos < 15; beam_pos++) {
453	        float phase_diff_degrees = phase_differences[beam_pos];
454	
455	        for(int element = 0; element < 16; element++) {
456	            float cumulative_phase_degrees = element * phase_diff_degrees;
457	            matrix1[beam_pos][element] = degreesTo7BitPhase(cumulative_phase_degrees);
458	        }
459	    }
460	
461	    // Matrix2: Positions 17-31 (negative phase differences)
462	    for(int beam_pos = 0; beam_pos < 15; beam_pos++) {
463	        float phase_diff_degrees = phase_differences[beam_pos + 16];
464	
465	        for(int element = 0; element < 16; element++) {
466	            float cumulative_phase_degrees = element * phase_diff_degrees;
467	            matrix2[beam_pos][element] = degreesTo7BitPhase(cumulative_phase_degrees);
468	        }
469	    }
470	
471	    // Vector_0: Position 16 (zero phase - broadside)
472	    for(int element = 0; element < 16; element++) {
473	        vector_0[element] = 0; // 0 in 7-bit = 0° phase
474	    }
475	
476	    uint8_t done[] = "Beam Matrices Initialized\r\n";
477	    HAL_UART_Transmit(&huart3, done, sizeof(done)-1, 1000);
478	}
