480	void executeChirpSequence(int num_chirps, float T1, float PRI1, float T2, float PRI2) {
481	    // NOTE: No per-chirp DIAG — this is a us/ns timing-critical path.
482	    // Only log entry params for post-mortem analysis.
483	    DIAG("SYS", "executeChirpSequence: num_chirps=%d T1=%.2f PRI1=%.2f T2=%.2f PRI2=%.2f",
484	         num_chirps, T1, PRI1, T2, PRI2);
485	    // First chirp sequence (microsecond timing)
486	    for(int i = 0; i < num_chirps; i++) {
487	        HAL_GPIO_TogglePin(GPIOD, GPIO_PIN_8); // New chirp signal to FPGA
488	        adarManager.pulseTXMode();
489	        delay_us((uint32_t)T1);
490	        adarManager.pulseRXMode();
491	        delay_us((uint32_t)(PRI1 - T1));
492	    }
493	
494	    delay_us((uint32_t)Guard);
495	
496	    // Second chirp sequence (nanosecond timing)
497	    for(int i = 0; i < num_chirps; i++) {
498	    	HAL_GPIO_TogglePin(GPIOD, GPIO_PIN_8); // New chirp signal to FPGA
499	        adarManager.pulseTXMode();
500	        delay_ns((uint32_t)(T2 * 1000));
501	        adarManager.pulseRXMode();
502	        delay_ns((uint32_t)((PRI2 - T2) * 1000));
503	
504	    }
505	}
