765	// Error recovery function
766	void attemptErrorRecovery(SystemError_t error) {
767	    DIAG_SECTION("SYS: attemptErrorRecovery");
768	    DIAG("SYS", "Attempting recovery from error code %d", error);
769	    char recovery_msg[80];
770	    snprintf(recovery_msg, sizeof(recovery_msg),
771	             "Attempting recovery from error: %d\r\n", error);
772	    HAL_UART_Transmit(&huart3, (uint8_t*)recovery_msg, strlen(recovery_msg), 1000);
773	
774	    switch (error) {
775	        case ERROR_ADF4382_TX_UNLOCK:
776	        case ERROR_ADF4382_RX_UNLOCK:
777	            // Re-initialize LO
778	            DIAG("LO", "Recovery: Re-initializing LO manager (SYNC_METHOD_TIMED)");
779	            ADF4382A_Manager_Init(&lo_manager, SYNC_METHOD_TIMED);
780	            HAL_Delay(100);
781	            DIAG("LO", "Recovery: LO re-init complete");
782	            break;
783	
784	        case ERROR_ADAR1000_COMM:
785	            // Reset ADAR1000 communication
786	            DIAG("BF", "Recovery: Re-initializing all ADAR1000 devices");
787	            adarManager.initializeAllDevices();
788	            HAL_Delay(50);
789	            DIAG("BF", "Recovery: ADAR1000 re-init complete");
790	            break;
791	
792	        case ERROR_IMU_COMM:
793	            // Re-initialize IMU
794	            DIAG("IMU", "Recovery: Re-initializing GY85 IMU");
795	            GY85_Init();
796	            HAL_Delay(100);
797	            DIAG("IMU", "Recovery: IMU re-init complete");
798	            break;
799	
800	        case ERROR_GPS_COMM:
801	            // GPS will auto-recover when signal returns
802	            DIAG("SYS", "Recovery: GPS error -- no action (auto-recover on signal)");
803	            break;
804	
805	        default:
806	            // For other errors, just log and continue
807	            DIAG_WARN("SYS", "Recovery: No specific handler for error %d", error);
808	            break;
809	    }
810	
811	    snprintf(recovery_msg, sizeof(recovery_msg),
812	             "Recovery attempt completed.\r\n");
813	    HAL_UART_Transmit(&huart3, (uint8_t*)recovery_msg, strlen(recovery_msg), 1000);
814	    DIAG("SYS", "attemptErrorRecovery COMPLETE");
815	}
