817	////////////////////////////////////////////////////////////////////////////////
818	//:::::RF POWER AMPLIFIER DAC5578 Emergency stop function using CLR pin/////////
819	////////////////////////////////////////////////////////////////////////////////
820	void Emergency_Stop(void) {
821	    DIAG_ERR("PA", ">>> EMERGENCY_STOP ACTIVATED <<<");
822	    /* Immediately clear all DAC outputs to zero using hardware CLR */
823	    DIAG_ERR("PA", "Clearing DAC1 outputs via CLR pin");
824	    DAC5578_ActivateClearPin(&hdac1);
825	    DIAG_ERR("PA", "Clearing DAC2 outputs via CLR pin");
826	    DAC5578_ActivateClearPin(&hdac2);
827	
828	    /* [GAP-3 FIX 1] Cut RF and PA power rails — DAC CLR alone is not enough.
829	     * With gate voltage cleared but VDD still energized, PAs can self-bias
830	     * or oscillate.  Disable everything in fast-to-slow order:
831	     *   1. TX mixers (stop RF immediately)
832	     *   2. PA 5V per-element supplies
833	     *   3. PA 5.5V bulk supply
834	     *   4. RFPA VDD enable
835	     */
836	    DIAG_ERR("PA", "Disabling TX mixers (GPIOD pin 11 LOW)");
837	    HAL_GPIO_WritePin(GPIOD, GPIO_PIN_11, GPIO_PIN_RESET);
838	
839	    DIAG_ERR("PA", "Cutting PA 5V supplies (PA1/PA2/PA3 LOW)");
840	    HAL_GPIO_WritePin(EN_P_5V0_PA1_GPIO_Port, EN_P_5V0_PA1_Pin, GPIO_PIN_RESET);
841	    HAL_GPIO_WritePin(EN_P_5V0_PA2_GPIO_Port, EN_P_5V0_PA2_Pin, GPIO_PIN_RESET);
842	    HAL_GPIO_WritePin(EN_P_5V0_PA3_GPIO_Port, EN_P_5V0_PA3_Pin, GPIO_PIN_RESET);
843	
844	    DIAG_ERR("PA", "Cutting PA 5.5V supply (EN_P_5V5_PA LOW)");
845	    HAL_GPIO_WritePin(EN_P_5V5_PA_GPIO_Port, EN_P_5V5_PA_Pin, GPIO_PIN_RESET);
846	
847	    DIAG_ERR("PA", "Disabling RFPA VDD (EN_DIS_RFPA_VDD LOW)");
848	    HAL_GPIO_WritePin(EN_DIS_RFPA_VDD_GPIO_Port, EN_DIS_RFPA_VDD_Pin, GPIO_PIN_RESET);
849	
850	    DIAG_ERR("PA", "All PA rails cut -- entering infinite hold loop (manual reset required)");
851	    /* Keep outputs cleared until reset.
852	     * MUST refresh IWDG here — otherwise the watchdog would reset the MCU,
853	     * re-running startup code which re-energizes PA rails. */
854	    while (1) {
855	        HAL_IWDG_Refresh(&hiwdg);
856	        HAL_Delay(100);
857	    }
858	}
