860	// Error response function
861	void handleSystemError(SystemError_t error) {
862	    if (error == ERROR_NONE) return;
863	
864	    error_count++;
865	    last_error = error;
866	    DIAG_ERR("SYS", "handleSystemError: error=%d error_count=%lu", error, error_count);
867	
868	    char error_msg[100];
869	    static const char* const error_strings[] = {
870	        "No error",
871	        "AD9523 Clock failure",
872	        "ADF4382 TX LO unlocked",
873	        "ADF4382 RX LO unlocked",
874	        "ADAR1000 communication error",
875	        "ADAR1000 temperature high",
876	        "IMU communication error",
877	        "BMP180 communication error",
878	        "GPS communication lost",
879	        "RF PA overcurrent detected",
880	        "RF PA bias fault",
881	        "Stepper motor fault",
882	        "FPGA communication error",
883	        "Power supply fault",
884	        "System temperature high",
885	        "Memory allocation failed",
886	        "Watchdog timeout"
887	    };
888	
889	    static_assert(sizeof(error_strings) / sizeof(error_strings[0]) == ERROR_COUNT,
890	                  "error_strings[] and SystemError_t enum are out of sync");
891	
892	    const char* err_name = (error >= 0 && error < (int)(sizeof(error_strings) / sizeof(error_strings[0])))
893	                           ? error_strings[error]
894	                           : "Unknown error";
895	
896	    snprintf(error_msg, sizeof(error_msg),
897	             "ERROR #%d: %s (Count: %lu)\r\n",
898	             error, err_name, error_count);
899	    HAL_UART_Transmit(&huart3, (uint8_t*)error_msg, strlen(error_msg), 1000);
900	
901	    // Blink LED pattern based on error code
902	    DIAG("SYS", "Blinking LED3 %d times for error code %d", (error % 5) + 1, error);
903	    for (int i = 0; i < (error % 5) + 1; i++) {
904	        HAL_GPIO_TogglePin(LED_3_GPIO_Port, LED_3_Pin);
905	        HAL_Delay(200);
906	    }
907	
908	    // Critical errors trigger emergency shutdown.
909	    //
910	    // Safety-critical range: any fault that can damage the PAs or leave the
911	    // system in an undefined state must cut the RF rails via Emergency_Stop().
912	    // This covers:
913	    //   ERROR_RF_PA_OVERCURRENT .. ERROR_POWER_SUPPLY (9..13) -- PA/supply faults
914	    //   ERROR_TEMPERATURE_HIGH  (14) -- >75 C on the PA thermal sensors;
915	    //                                  without cutting bias + 5V/5V5/RFPA rails
916	    //                                  the GaN QPA2962 stage can thermal-runaway.
917	    //   ERROR_WATCHDOG_TIMEOUT  (16) -- health-check loop has stalled (>60 s);
918	    //                                  transmitter state is unknown, safest to
919	    //                                  latch Emergency_Stop rather than rely on
920	    //                                  IWDG reset (which re-energises the rails).
921	    if ((error >= ERROR_RF_PA_OVERCURRENT && error <= ERROR_POWER_SUPPLY) ||
922	        error == ERROR_TEMPERATURE_HIGH ||
923	        error == ERROR_WATCHDOG_TIMEOUT) {
924	        DIAG_ERR("SYS", "CRITICAL ERROR (code %d: %s) -- initiating Emergency_Stop()", error, err_name);
925	        snprintf(error_msg, sizeof(error_msg),
926	                 "CRITICAL ERROR! Initiating emergency shutdown.\r\n");
927	        HAL_UART_Transmit(&huart3, (uint8_t*)error_msg, strlen(error_msg), 1000);
928	
929	        /* [GAP-3 FIX 5] Set flag BEFORE Emergency_Stop() — the function
930	         * never returns (infinite loop), so the line after it was dead code. */
931	        system_emergency_state = true;
932	        Emergency_Stop();
933	        /* NOTREACHED — Emergency_Stop() loops forever */
934	    }
935	
936	    // For non-critical errors, attempt recovery
937	    if (!system_emergency_state) {
938	        DIAG("SYS", "Non-critical error -- attempting recovery");
939	        attemptErrorRecovery(error);
940	    }
941	}
