944	// System health monitoring function
945	bool checkSystemHealthStatus(void) {
946	    SystemError_t error = checkSystemHealth();
947	
948	    if (error != ERROR_NONE) {
949	        DIAG_ERR("SYS", "checkSystemHealthStatus: error detected (code %d), calling handleSystemError()", error);
950	        handleSystemError(error);
951	
952	        // If we're in emergency state or too many errors, shutdown
953	        if (system_emergency_state || error_count > 10) {
954	            DIAG_ERR("SYS", "checkSystemHealthStatus returning FALSE (emergency=%s error_count=%lu)",
955	                     system_emergency_state ? "true" : "false", error_count);
956	            return false;
957	        }
958	    }
959	
960	    return true;
961	}
