963	// Get system status for GUI
964	// Get system status for GUI with 8 temperature variables
965	void getSystemStatusForGUI(char* status_buffer, size_t buffer_size) {
966	    // Build status string directly in the output buffer using offset-tracked
967	    // snprintf.  Each call returns the number of chars written (excluding NUL),
968	    // so we advance 'off' and shrink 'rem' to guarantee we never overflow.
969	    size_t off = 0;
970	    size_t rem = buffer_size;
971	    int w;
972	
973	    // Basic status
974	    if (system_emergency_state) {
975	        w = snprintf(status_buffer + off, rem, "System Status: EMERGENCY_STOP|");
976	    } else {
977	        w = snprintf(status_buffer + off, rem, "System Status: NORMAL|");
978	    }
979	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
980	
981	    // Error information
982	    w = snprintf(status_buffer + off, rem, "LastError:%d|ErrorCount:%lu|",
983	                 last_error, error_count);
984	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
985	
986	    // Sensor status
987	    w = snprintf(status_buffer + off, rem, "IMU:%.1f,%.1f,%.1f|GPS:%.6f,%.6f|ALT:%.1f|",
988	                 Pitch_Sensor, Roll_Sensor, Yaw_Sensor,
989	                 RADAR_Latitude, RADAR_Longitude, RADAR_Altitude);
990	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
991	
992	    // LO Status
993	    bool tx_locked, rx_locked;
994	    ADF4382A_CheckLockStatus(&lo_manager, &tx_locked, &rx_locked);
995	    w = snprintf(status_buffer + off, rem, "LO_TX:%s|LO_RX:%s|",
996	                 tx_locked ? "LOCKED" : "UNLOCKED",
997	                 rx_locked ? "LOCKED" : "UNLOCKED");
998	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
999	
1000	    // Temperature readings (8 variables)
1001	    Temperature_1 = ADS7830_Measure_SingleEnded(&hadc3, 0);
1002	    Temperature_2 = ADS7830_Measure_SingleEnded(&hadc3, 1);
1003	    Temperature_3 = ADS7830_Measure_SingleEnded(&hadc3, 2);
1004	    Temperature_4 = ADS7830_Measure_SingleEnded(&hadc3, 3);
1005	    Temperature_5 = ADS7830_Measure_SingleEnded(&hadc3, 4);
1006	    Temperature_6 = ADS7830_Measure_SingleEnded(&hadc3, 5);
1007	    Temperature_7 = ADS7830_Measure_SingleEnded(&hadc3, 6);
1008	    Temperature_8 = ADS7830_Measure_SingleEnded(&hadc3, 7);
1009	
1010	    // Format all 8 temperature variables
1011	    w = snprintf(status_buffer + off, rem,
1012	                 "T1:%.1f|T2:%.1f|T3:%.1f|T4:%.1f|T5:%.1f|T6:%.1f|T7:%.1f|T8:%.1f|",
1013	                 Temperature_1, Temperature_2, Temperature_3, Temperature_4,
1014	                 Temperature_5, Temperature_6, Temperature_7, Temperature_8);
1015	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
1016	
1017	    // RF Power Amplifier status (if enabled)
1018	    if (PowerAmplifier) {
1019	        float avg_current = 0.0f;
1020	        for (int i = 0; i < 16; i++) {
1021	            avg_current += Idq_reading[i];
1022	        }
1023	        avg_current /= 16.0f;
1024	
1025	        w = snprintf(status_buffer + off, rem, "PA_AvgCurrent:%.2f|PA_Enabled:%d|",
1026	                     avg_current, PowerAmplifier);
1027	        if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
1028	    }
1029	
1030	    // Radar operation status
1031	    w = snprintf(status_buffer + off, rem, "BeamPos:%d|Azimuth:%d|ChirpCount:%d|",
1032	                 n, y, m);
1033	    if (w > 0 && (size_t)w < rem) { off += (size_t)w; rem -= (size_t)w; }
1034	
1035	    // NUL termination guaranteed by snprintf, but be safe
