1309	void initializeBeamMatricesWithSteeringAngles() {
1310	    const float wavelength = 0.02857f; // 10.5 GHz wavelength in meters
1311	    const float element_spacing = wavelength / 2.0f;
1312	
1313	    // Calculate steering angles from phase differences
1314	    float steering_angles[31];
1315	    for(int i = 0; i < 31; i++) {
1316	        float phase_diff_rad = phase_differences[i] * M_PI / 180.0f;
1317	        steering_angles[i] = asin((phase_diff_rad * wavelength) / (2 * M_PI * element_spacing)) * 180.0f / M_PI;
1318	    }
1319	
1320	    // Matrix1: Positive angles (positions 1-15)
1321	    for(int beam_pos = 0; beam_pos < 15; beam_pos++) {
1322	        float angle = steering_angles[beam_pos];
1323	
1324	        for(int element = 0; element < 16; element++) {
1325	            // Calculate phase shift for linear array
1326	            float phase_shift_rad = (2 * M_PI * element_spacing * element * sin(angle * M_PI / 180.0f)) / wavelength;
1327	            float phase_degrees = phase_shift_rad * 180.0f / M_PI;
1328	
1329	            // Wrap to 0-360 degrees
1330	            while(phase_degrees < 0) phase_degrees += 360;
1331	            while(phase_degrees >= 360) phase_degrees -= 360;
1332	
1333	            matrix1[beam_pos][element] = (uint8_t)((phase_degrees / 360.0f) * 128);
1334	        }
1335	    }
1336	
1337	    // Matrix2: Negative angles (positions 17-31)
1338	    for(int beam_pos = 0; beam_pos < 15; beam_pos++) {
1339	        float angle = steering_angles[beam_pos + 16];
1340	
1341	        for(int element = 0; element < 16; element++) {
1342	            float phase_shift_rad = (2 * M_PI * element_spacing * element * sin(angle * M_PI / 180.0f)) / wavelength;
1343	            float phase_degrees = phase_shift_rad * 180.0f / M_PI;
1344	
1345	            while(phase_degrees < 0) phase_degrees += 360;
1346	            while(phase_degrees >= 360) phase_degrees -= 360;
1347	
1348	            matrix2[beam_pos][element] = (uint8_t)((phase_degrees / 360.0f) * 128);
1349	        }
1350	    }
1351	}
