1531	  mxc = M11*(mx-mbias[0]) + M12*(my-mbias[1]) +M13*(mz-mbias[2]);
1532	  myc = M21*(mx-mbias[0]) + M22*(my-mbias[1]) +M23*(mz-mbias[2]);
1533	  mzc = M31*(mx-mbias[0]) + M32*(my-mbias[1]) +M33*(mz-mbias[2]);
1534	
1535	  mx = mxc;
1536	  my = myc;
1537	  mz = mzc;
1538	
1539	  float norm = sqrt((mx*mx) + (my*my) + (mz*mz));
1540	  mx /=norm;
1541	  my /=norm;
1542	  mz /=norm;
1543	
1544	  /***************************************************************/
1545	  /*********************IMU Complementary Filter******************/
1546	  /***************************************************************/
1547	    RxAcc = ax;
1548	    RyAcc = ay;
1549	    RzAcc = az;
1550	
1551	    Rate_Ayz_1 = gx;
1552	    Rate_Axz_1 = gy;
1553	    Rate_Axy_1 = gz;
1554	
1555	    Rate_Ayz_1 = Rate_Ayz_1*0.01745;//Convertion from °/s to Radians/s
1556	    Rate_Axz_1 = Rate_Axz_1*0.01745;
1557	    Rate_Axy_1 = Rate_Axy_1*0.01745;
1558	
1559	    /*Combining Accelerometer & Gyroscope Data*/
1560	    Axz_0 = atan2(RxEst_0,RzEst_0);
1561	    Ayz_0 = atan2(RyEst_0,RzEst_0);
1562	    Axy_0 = atan2(RxEst_0,RyEst_0);
1563	
1564	    now_timeperiod = micros();
1565	
1566	    Time_Period = now_timeperiod - lasttime_timeperiod;
1567	
1568	    Axz_1= Axz_0 + Rate_Axz_1*Time_Period*0.000001;
1569	    Ayz_1= Ayz_0 + Rate_Ayz_1*Time_Period*0.000001;
1570	    Axy_1= Axy_0 + Rate_Axy_1*Time_Period*0.000001;
1571	
1572	    lasttime_timeperiod = now_timeperiod;
1573	
1574	    RxGyro = sin(Axz_1)/(sqrt(1.0 + cos(Axz_1)*cos(Axz_1) * tan(Ayz_1)*tan(Ayz_1)));
1575	    RyGyro = sin(Ayz_1)/(sqrt(1.0 + cos(Ayz_1)*cos(Ayz_1) * tan(Axz_1)*tan(Axz_1)));
1576	    if(RzEst_0 >= 0){
1577	      RzGyro = 1.0*sqrt(1 - RxGyro*RxGyro - RyGyro*RyGyro);
1578	    }
1579	    else {
1580	      RzGyro = -1*sqrt(1 - RxGyro*RxGyro - RyGyro*RyGyro);
1581	    }
1582	
1583	    RxEst_1 = RxAcc*0.5 + RxGyro*0.5 ;// Weight of Gyro. over Acc.
1584	    RyEst_1 = RyAcc*0.5 + RyGyro*0.5 ;
1585	    RzEst_1 = RzAcc*0.5 + RzGyro*0.5 ;
1586	
1587	    R_Est = sqrt(RxEst_1*RxEst_1+RyEst_1*RyEst_1+RzEst_1*RzEst_1);
1588	
1589	    Pitch_Sensor = atan2(RxEst_1,sqrt(RyEst_1*RyEst_1)+(RzEst_1*RzEst_1))*180/PI;
1590	    Roll_Sensor = atan2(RyEst_1,sqrt(RxEst_1*RxEst_1)+(RzEst_1*RzEst_1))*180/PI;
1591	
1592	    float magRawX = mx*cos(Pitch_Sensor*PI/180.0f)  - mz*sin(Pitch_Sensor*PI/180.0f);
1593		float magRawY = mx*sin(Roll_Sensor*PI/180.0f)*sin(Pitch_Sensor*PI/180.0f) + my*cos(Roll_Sensor*PI/180.0f)- mz*sin(Roll_Sensor*PI/180.0f)*cos(Pitch_Sensor*PI/180.0f);
1594	    Yaw_Sensor = (180*atan2(magRawY,magRawX)/PI) - Mag_Declination;
1595	
1596	    if(Yaw_Sensor<0)Yaw_Sensor+=360;
1597	
1598	    // Override magnetometer heading with UM982 dual-antenna heading when available
1599	    if (um982_is_heading_valid(&um982)) {
1600	        Yaw_Sensor = um982_get_heading(&um982);
1601	    }
1602	
1603	    RxEst_0 = RxEst_1;
1604	    RyEst_0 = RyEst_1;
1605	    RzEst_0 = RzEst_1;
1606	
1607	    HAL_Delay(300);
1608	
1609	  }
1610	
1611	    ///////////////////////////////////////////////////////////////////////////////////
1612	    ///////////////////////////////////BAROMETER BMP180////////////////////////////////
1613	    ///////////////////////////////////////////////////////////////////////////////////
1614	    DIAG_SECTION("BAROMETER INIT (BMP180)");
1615	    DIAG("IMU", "Reading 5 barometer samples for altitude baseline");
1616	  	for(int i = 0; i<5 ; i++){
1617			float BMP_Perssure = myBMP.getPressure();
1618			RADAR_Altitude = 44330*(1-(pow((BMP_Perssure/101325),(1/5.255))));
1619			HAL_Delay(100);
1620	  	}
1621	    DIAG("IMU", "Barometer init complete, RADAR_Altitude baseline set");
1622	
1623	    ///////////////////////////////////////////////////////////////////////////////////
1624	    ///////////////////////////////////////ADF4382/////////////////////////////////////
1625	    ///////////////////////////////////////////////////////////////////////////////////
1626	    DIAG_SECTION("ADF4382A LO INIT");
1627	    printf("Starting ADF4382A Radar LO System...\n");
1628	    printf("Using SPI4 with TIMED SYNCHRONIZATION (60 MHz clocks)\n");
1629	
1630	    // Initialize LO manager with TIMED synchronization
1631	    DIAG("LO", "Calling ADF4382A_Manager_Init(sync=SYNC_METHOD_TIMED)");
1632	    uint32_t lo_init_start = HAL_GetTick();
1633	    int ret = ADF4382A_Manager_Init(&lo_manager, SYNC_METHOD_TIMED);
1634	    DIAG("LO", "ADF4382A_Manager_Init returned %d (took %lu ms)",
1635	         ret, (unsigned long)(HAL_GetTick() - lo_init_start));
1636	
1637	    /* [Bug #4 FIXED] Check init return code BEFORE calling phase shift.
1638	     * Previously SetPhaseShift/Strobe were called before this check. */
1639	    if (ret != ADF4382A_MANAGER_OK) {
1640	        printf("LO Manager initialization failed: %d\n", ret);
1641	        DIAG_ERR("LO", "Manager init FAILED (ret=%d) -- calling Error_Handler()", ret);
1642	        Error_Handler();
1643	    }
1644	
1645	    // Set phase shift (e.g., 500 ps for TX, 500 ps for RX)
1646	    int ps_ret = ADF4382A_SetPhaseShift(&lo_manager, 500, 500);
1647	    DIAG("LO", "ADF4382A_SetPhaseShift(500, 500) returned %d", ps_ret);
1648	
1649	    // Strobe to apply phase shifts
1650	    int strobe_tx_ret = ADF4382A_StrobePhaseShift(&lo_manager, 0); // TX device
1651	    int strobe_rx_ret = ADF4382A_StrobePhaseShift(&lo_manager, 1); // RX device
1652	    DIAG("LO", "StrobePhaseShift TX returned %d, RX returned %d", strobe_tx_ret, strobe_rx_ret);
1653	
1654	    // Check initial lock status
1655	    bool tx_locked, rx_locked;
1656	    DIAG("LO", "Checking initial lock status...");
1657	    ret = ADF4382A_CheckLockStatus(&lo_manager, &tx_locked, &rx_locked);
1658	    if (ret == ADF4382A_MANAGER_OK) {
1659	        printf("Initial Lock Status - TX: %s, RX: %s\n",
1660	               tx_locked ? "LOCKED" : "UNLOCKED",
1661	               rx_locked ? "LOCKED" : "UNLOCKED");
1662	        DIAG("LO", "Initial lock: TX=%s RX=%s", tx_locked ? "LOCKED" : "UNLOCKED", rx_locked ? "LOCKED" : "UNLOCKED");
1663	    } else {
1664	        DIAG_ERR("LO", "CheckLockStatus returned %d", ret);
1665	    }
1666	    // Wait for both LOs to lock
1667	        DIAG("LO", "Entering lock-wait loop (max 10 s = 100 x 100 ms)");
1668	        uint32_t lock_wait_start = HAL_GetTick();
1669	        uint32_t lock_timeout = 0;
1670	        while (!(tx_locked && rx_locked) && lock_timeout < 100) {
1671	            HAL_Delay(100);
1672	            ADF4382A_CheckLockStatus(&lo_manager, &tx_locked, &rx_locked);
1673	            lock_timeout++;
1674	
1675	            if (lock_timeout % 10 == 0) {
1676	                printf("Waiting for LO lock... TX: %s, RX: %s\n",
1677	                       tx_locked ? "LOCKED" : "UNLOCKED",
1678	                       rx_locked ? "LOCKED" : "UNLOCKED");
1679	                DIAG("LO", "Lock poll #%lu: TX=%s RX=%s",
1680	                     (unsigned long)lock_timeout,
1681	                     tx_locked ? "LOCKED" : "UNLOCKED",
1682	                     rx_locked ? "LOCKED" : "UNLOCKED");
1683	            }
1684	        }
1685	        DIAG_ELAPSED("LO", "Lock wait loop", lock_wait_start);
1686	
1687	        if (tx_locked && rx_locked) {
1688	            printf("Both LOs locked successfully!\n");
1689	            printf("Synchronization ready - 60 MHz clocks on SYNCP/SYNCN pins\n");
1690	            DIAG("LO", "Both LOs LOCKED after %lu iterations", (unsigned long)lock_timeout);
1691	            // - 60 MHz phase-aligned clocks on SYNCP/SYNCN pins
1692	            // - SYNC pin connected for triggering
1693	
1694	            // When ready to synchronize:
1695	            DIAG("LO", "Calling TriggerTimedSync to pulse sw_sync on both PLLs");
1696	            ADF4382A_TriggerTimedSync(&lo_manager);
1697	            // At this point, the SYNC pin can be toggled to trigger synchronization
1698	        } else {
1699	            printf("LO lock timeout! TX: %s, RX: %s\n",
1700	                   tx_locked ? "LOCKED" : "UNLOCKED",
1701	                   rx_locked ? "LOCKED" : "UNLOCKED");
1702	            DIAG_ERR("LO", "Lock TIMEOUT after %lu iterations! TX=%s RX=%s",
1703	                     (unsigned long)lock_timeout,
1704	                     tx_locked ? "LOCKED" : "UNLOCKED",
1705	                     rx_locked ? "LOCKED" : "UNLOCKED");
1706	        }
1707	
1708	  // check if there is a lock via direct GPIO (independent of register read above)
1709	  DIAG("LO", "Direct GPIO lock detect pins:");
1710	  DIAG_GPIO("LO", "ADF4382_TX_LKDET", ADF4382_TX_LKDET_GPIO_Port, ADF4382_TX_LKDET_Pin);
1711	  DIAG_GPIO("LO", "ADF4382_RX_LKDET", ADF4382_RX_LKDET_GPIO_Port, ADF4382_RX_LKDET_Pin);
1712	  if(HAL_GPIO_ReadPin (ADF4382_TX_LKDET_GPIO_Port, ADF4382_TX_LKDET_Pin))
1713	  {
1714	      // Set The LED_1 ON!
1715	      HAL_GPIO_WritePin(LED_1_GPIO_Port, LED_1_Pin, GPIO_PIN_SET);
1716	      DIAG("LO", "TX lock detected via GPIO -- LED_1 ON");
1717	  }
1718	  else
1719	  {
1720	      // Else .. Turn LED_1 OFF!
1721	      HAL_GPIO_WritePin(LED_1_GPIO_Port, LED_1_Pin, GPIO_PIN_RESET);
1722	      DIAG_WARN("LO", "TX NOT locked via GPIO -- LED_1 OFF");
1723	  }
1724	
1725	  if(HAL_GPIO_ReadPin (ADF4382_RX_LKDET_GPIO_Port, ADF4382_RX_LKDET_Pin))
1726	  {
1727	      // Set The LED_2 ON!
1728	      HAL_GPIO_WritePin(LED_2_GPIO_Port, LED_2_Pin, GPIO_PIN_SET);
1729	      DIAG("LO", "RX lock detected via GPIO -- LED_2 ON");
1730	  }
1731	  else
1732	  {
1733	      // Else .. Turn LED_2 OFF!
1734	      HAL_GPIO_WritePin(LED_2_GPIO_Port, LED_2_Pin, GPIO_PIN_RESET);
1735	      DIAG_WARN("LO", "RX NOT locked via GPIO -- LED_2 OFF");
1736	  }
1737	
1738	
1739	  //////////////////////////////////////////////////////////////////////////////////////
1740	  /////////////////////////////////////ADAR1000/////////////////////////////////////////
1741	  //////////////////////////////////////////////////////////////////////////////////////
1742	
1743	  //Power sequencing ADAR1000
1744	  DIAG_SECTION("ADAR1000 POWER SEQUENCING");
1745	
1746	  //Tell FPGA to turn off TX RF signal by disabling Mixers
1747	  DIAG("BF", "Disabling TX mixers (GPIOD pin 11 LOW)");
1748	  HAL_GPIO_WritePin(GPIOD, GPIO_PIN_11, GPIO_PIN_RESET);
1749	
1750	  DIAG("PWR", "Enabling 3.3V ADAR12 + ADAR34 rails");
1751	  HAL_GPIO_WritePin(EN_P_3V3_ADAR12_GPIO_Port,EN_P_3V3_ADAR12_Pin,GPIO_PIN_SET);
1752	  HAL_GPIO_WritePin(EN_P_3V3_ADAR34_GPIO_Port,EN_P_3V3_ADAR34_Pin,GPIO_PIN_SET);
1753	  HAL_Delay(500);
1754	  DIAG("PWR", "Enabling 5.0V ADAR rail");
1755	  HAL_GPIO_WritePin(EN_P_5V0_ADAR_GPIO_Port,EN_P_5V0_ADAR_Pin,GPIO_PIN_SET);
1756	  HAL_Delay(500);
1757	  DIAG("PWR", "ADAR1000 power sequencing complete");
1758	
1759	  // System startup message
1760	      uint8_t startup_msg[] = "Starting Phased Array RADAR System...\r\n";
1761	      HAL_UART_Transmit(&huart3, startup_msg, sizeof(startup_msg)-1, 1000);
1762	
1763	      DIAG("BF", "Calling systemPowerUpSequence()");
1764	      // Power up sequence
1765	      systemPowerUpSequence();
1766	
1767	      DIAG("BF", "Calling initializeBeamMatrices()");
1768	      // Initialize beam matrices
1769	      initializeBeamMatrices();
1770	
1771	      // Print system status
1772	      printSystemStatus();
1773	      DIAG("SYS", "System init complete -- entering main loop");
1774	
1775	  	//////////////////////////////////////////////////////////////////////////////////////
1776	    //////////////////////////////////////////GPS/////////////////////////////////////////
1777	    //////////////////////////////////////////////////////////////////////////////////////
1778	  DIAG_SECTION("GPS INIT (UM982)");
1779	  DIAG("GPS", "Initializing UM982 on UART5 @ 115200 (baseline=50cm, tol=3cm)");
1780	  if (!um982_init(&um982, &huart5, 50.0f, 3.0f)) {
1781	      DIAG_WARN("GPS", "UM982 init: no VERSIONA response -- module may need more time");
1782	      // Not fatal: module may still start sending NMEA data after boot
1783	  } else {
1784	      DIAG("GPS", "UM982 init OK -- VERSIONA received");
1785	  }
1786	
1787	  // Collect GPS data for a few seconds (non-blocking pump)
1788	  DIAG("GPS", "Pumping GPS for 5 seconds to acquire initial fix...");
1789	  {
1790	      uint32_t gps_start = HAL_GetTick();
1791	      while (HAL_GetTick() - gps_start < 5000) {
1792	          um982_process(&um982);
1793	          HAL_Delay(10);
1794	      }
1795	  }
1796	  RADAR_Longitude = um982_get_longitude(&um982);
1797	  RADAR_Latitude = um982_get_latitude(&um982);
1798	  DIAG("GPS", "Initial position: lat=%.6f lon=%.6f fix=%d sats=%d",
1799	       RADAR_Latitude, RADAR_Longitude,
1800	       um982_get_fix_quality(&um982), um982_get_num_sats(&um982));
1801	
1802	  // Re-apply heading after GPS init so the north-alignment stepper move uses
1803	  // UM982 dual-antenna heading when available.
1804	  if (um982_is_heading_valid(&um982)) {
1805	      Yaw_Sensor = um982_get_heading(&um982);
1806	  }
1807	
1808	  //move Stepper to position 1 = 0°
1809	  HAL_GPIO_WritePin(STEPPER_CW_P_GPIO_Port, STEPPER_CW_P_Pin, GPIO_PIN_RESET);//Set stepper motor spinning direction to CCW
1810	  //Point Stepper to North
1811	  for(int i= 0;i<(int)(Yaw_Sensor*Stepper_steps/360);i++){
1812		  HAL_GPIO_WritePin(STEPPER_CLK_P_GPIO_Port, STEPPER_CLK_P_Pin, GPIO_PIN_SET);
1813		  delay_us(500);
1814		  HAL_GPIO_WritePin(STEPPER_CLK_P_GPIO_Port, STEPPER_CLK_P_Pin, GPIO_PIN_RESET);
1815		  delay_us(500);
1816	  }
1817	
1818	  /***************************************************************/
1819	  /**********wait for GUI start flag and Send Lat/Long/alt********/
1820	  /***************************************************************/
1821	
1822	  GPS_Data_t gps_data;
1823	  // Binary packet structure:
1824	  // [Header 4 bytes][Latitude 8 bytes][Longitude 8 bytes][Altitude 4 bytes][Pitch 4 bytes][CRC 2 bytes]
1825	  gps_data = {RADAR_Latitude, RADAR_Longitude, RADAR_Altitude, Pitch_Sensor, HAL_GetTick()};
1826	  if (!GPS_SendBinaryToGUI(&gps_data)) {
1827	      const uint8_t gps_send_error[] = "GPS binary send failed\r\n";
1828	      HAL_UART_Transmit(&huart3, (uint8_t*)gps_send_error, sizeof(gps_send_error) - 1, 1000);
1829	  }
1830	
1831	  /* [STM32-006 FIXED] Removed blocking do-while loop that waited for
1832	   * usbHandler.isStartFlagReceived().  The production V7 PyQt GUI does not
1833	   * send the legacy 4-byte start flag [23,46,158,237], so this loop hung
1834	   * the MCU at boot indefinitely.  The USB settings handshake (if ever
1835	   * re-enabled) should be handled non-blocking in the main loop. */
1836	
1837	  /***************************************************************/
1838	  /************RF Power Amplifier Powering up sequence************/
1839	  /***************************************************************/
1840	  if(PowerAmplifier){
1841		  DIAG_SECTION("PA: RF Power Amplifier power-up sequence");
1842		  /* Initialize DACs */
1843		  /* DAC1: Address 0b1001000 = 0x48 */
1844		  DIAG("PA", "Initializing DAC1 (I2C1, addr=0x48, 8-bit)");
1845		  if (!DAC5578_Init(&hdac1, &hi2c1, 0x48, 8,
1846				  DAC_1_VG_LDAC_GPIO_Port, DAC_1_VG_LDAC_Pin,
1847				  DAC_1_VG_CLR_GPIO_Port, DAC_1_VG_CLR_Pin)) {
1848			  DIAG_ERR("PA", "DAC1 init FAILED -- calling Error_Handler()");
1849			  Error_Handler();
1850		  }
1851		  DIAG("PA", "DAC1 init OK");
1852	
1853		  /* DAC2: Address 0b1001001 = 0x49 */
1854		  DIAG("PA", "Initializing DAC2 (I2C1, addr=0x49, 8-bit)");
1855		  if (!DAC5578_Init(&hdac2, &hi2c1, 0x49, 8,
1856				  DAC_2_VG_LDAC_GPIO_Port, DAC_2_VG_LDAC_Pin,
1857				  DAC_2_VG_CLR_GPIO_Port, DAC_2_VG_CLR_Pin)) {
1858			  DIAG_ERR("PA", "DAC2 init FAILED -- calling Error_Handler()");
1859			  Error_Handler();
1860		  }
1861		  DIAG("PA", "DAC2 init OK");
1862	
1863		  /* Configure clear code behavior */
1864		  DIAG("PA", "Setting clear code to ZERO on both DACs");
1865		  DAC5578_SetClearCode(&hdac1, DAC5578_CLR_CODE_ZERO); // Clear to 0V on CLR pulse
1866		  DAC5578_SetClearCode(&hdac2, DAC5578_CLR_CODE_ZERO); // Clear to 0V on CLR pulse
1867	
1868		  /* Configure LDAC so all channels update simultaneously on hardware LDAC */
1869		  DIAG("PA", "Setting LDAC mask=0xFF on both DACs (all channels respond)");
1870		  DAC5578_SetupLDAC(&hdac1, 0xFF); // All channels respond to LDAC
1871		  DAC5578_SetupLDAC(&hdac2, 0xFF); // All channels respond to LDAC
1872	
1873		  //set Vg [1-8] to -3.98V -> input opamp = 1.63058V->126(8bits)
1874		  DIAG("PA", "Writing initial DAC_val=%d to DAC1 channels 0-7", DAC_val);
1875		  for(int channel = 0; channel < 8; channel++){
1876			  DAC5578_WriteAndUpdateChannelValue(&hdac1, channel, DAC_val);
1877		  }
1878	
1879		  //set Vg [9-16] to -3.98V -> input opamp = 1.63058V->126(8bits)
1880		  DIAG("PA", "Writing initial DAC_val=%d to DAC2 channels 0-7", DAC_val);
1881		  for(int channel = 0; channel < 8; channel++){
1882			  DAC5578_WriteAndUpdateChannelValue(&hdac2, channel, DAC_val);
1883		  }
1884	
1885		  /* Optional: Use hardware LDAC for simultaneous update of all channels */
1886		  DIAG("PA", "Pulsing LDAC on both DACs for simultaneous update");
1887		  HAL_GPIO_WritePin(DAC_1_VG_LDAC_GPIO_Port, DAC_1_VG_LDAC_Pin, GPIO_PIN_RESET);
1888		  HAL_GPIO_WritePin(DAC_2_VG_LDAC_GPIO_Port, DAC_2_VG_LDAC_Pin, GPIO_PIN_RESET);
1889		  HAL_Delay(1);
1890		  HAL_GPIO_WritePin(DAC_1_VG_LDAC_GPIO_Port, DAC_1_VG_LDAC_Pin, GPIO_PIN_SET);
1891		  HAL_GPIO_WritePin(DAC_2_VG_LDAC_GPIO_Port, DAC_2_VG_LDAC_Pin, GPIO_PIN_SET);
1892	
1893		  //Enable RF Power Amplifier VDD = 22V
1894		  DIAG("PA", "Enabling RFPA VDD=22V (EN_DIS_RFPA_VDD HIGH)");
1895		  HAL_GPIO_WritePin(EN_DIS_RFPA_VDD_GPIO_Port, EN_DIS_RFPA_VDD_Pin, GPIO_PIN_SET);
1896	
1897		  /* Initialize ADCs with correct addresses */
1898		  /* ADC1: Address 0x48, Single-Ended mode, Internal Ref ON + ADC ON */
1899		  DIAG("PA", "Initializing ADC1 (I2C2, addr=0x48, single-ended, ref+adc ON)");
1900		  if (!ADS7830_Init(&hadc1, &hi2c2, 0x48,
1901							ADS7830_SDMODE_SINGLE, ADS7830_PDIRON_ADON)) {
1902			  DIAG_ERR("PA", "ADC1 init FAILED -- calling Error_Handler()");
1903			  Error_Handler();
1904		  }
1905		  DIAG("PA", "ADC1 init OK");
1906	
1907		  /* ADC2: Address 0x4A, Single-Ended mode, Internal Ref ON + ADC ON */
1908		  DIAG("PA", "Initializing ADC2 (I2C2, addr=0x4A, single-ended, ref+adc ON)");
1909		  if (!ADS7830_Init(&hadc2, &hi2c2, 0x4A,
1910							ADS7830_SDMODE_SINGLE, ADS7830_PDIRON_ADON)) {
1911			  DIAG_ERR("PA", "ADC2 init FAILED -- calling Error_Handler()");
1912			  Error_Handler();
1913		  }
1914		  DIAG("PA", "ADC2 init OK");
1915	
1916		  /* Read all 8 channels from ADC1 and calculate Idq */
1917		  DIAG("PA", "Reading initial Idq from ADC1 channels 0-7");
1918		  for (uint8_t channel = 0; channel < 8; channel++) {
1919			  adc1_readings[channel] = ADS7830_Measure_SingleEnded(&hadc1, channel);
1920			  Idq_reading[channel]= (3.3/255)*adc1_readings[channel]/(50*0.005);//Idq=Vadc/(GxRshunt)//G_INA241A3=50;Rshunt=5mOhms
1921			  DIAG("PA", "  ADC1 ch%d: raw=%d Idq=%.3fA", channel, adc1_readings[channel], Idq_reading[channel]);
1922		  }
1923	
1924		  /* Read all 8 channels from ADC2 and calculate Idq*/
1925		  DIAG("PA", "Reading initial Idq from ADC2 channels 0-7");
1926		  for (uint8_t channel = 0; channel < 8; channel++) {
1927			  adc2_readings[channel] = ADS7830_Measure_SingleEnded(&hadc2, channel);
1928			  Idq_reading[channel+8]= (3.3/255)*adc2_readings[channel]/(50*0.005);//Idq=Vadc/(GxRshunt)//G_INA241A3=50;Rshunt=5mOhms

