        return -1;
    }

    // optionally manual sync
    DIAG("CLK", "Triggering manual ad9523_sync()");
    ad9523_sync(dev);
    DIAG("CLK", "AD9523 configuration complete -- all outputs should be active");

    // keep device pointer globally if needed (dev)
    return 0;
